mapper.sql:
SELECT T.ID, T.NAME, T.TYPE_MONEY, T.SEND_TYPE, T.MIN_AMOUNT, T.MAX_AMOUNT, T.SEND_START_DATE, T.SEND_END_DATE, T.USE_START_DATE, T.USE_END_DATE, T.MIN_GOODS_AMOUNT, T.MIN_TRANSMIT_NUM FROM MALL_COUPON T WHERE 1=1
AND T.ID = #{params.id}
AND T.NAME LIKE '%${params.name}%'

mapper.select:
select a.*, b.coupon_number, b.user_id, b.coupon_status, b.id user_coupon_id
from mall_coupon a
         left join mall_user_coupon b on a.id = b.coupon_id
where 1 = 1
  and b.id = #{id}
  and b.user_id = #{userId}

select a.`id`, a.`name`, a.`type_money` as type_money, a.`send_type`, a.`min_amount`, a.`max_amount`, a.`send_start_date`, a.`send_end_date`, a.`use_start_date`, a.`use_end_date`, a.`min_goods_amount`, a.min_transmit_num from mall_coupon a left join mall_coupon b on a.send_type = b.send_type and b.type_money > a.type_money where 1 = 1 and a.use_end_date >= now() and now() >= a.use_start_date and b.id is null
and a.send_type = #{sendType}
limit 0, 1

select * from mall_coupon a where 1 = 1
and send_type in
#{item}
and a.use_end_date >= now() and now() >= a.use_start_date
order by ${sidx} ${order}
order by a.id desc
